using System;

class Program
{
    static void Main()
    {
        bool theoryPassed = CheckTheory();
        bool practicePassed = CheckPractice();

        ShowFinalResult(theoryPassed, practicePassed);
    }

    // This method checks the theory score
    static bool CheckTheory()
    {
        int theoryScore = 75;

        if (theoryScore >= 60)
        {
            return true;
        }
        else
        {
            return false;
        }
    }

    // This method checks the practice score
    static bool CheckPractice()
    {
        int practiceScore = 80;

        if (practiceScore >= 60)
        {
            return true;
        }
        else
        {
            return false;
        }
    }

    // This method receives both results and prints the final message
    static void ShowFinalResult(bool theoryPassed, bool practicePassed)
    {
        if (theoryPassed == true && practicePassed == true)
        {
            Console.WriteLine("Test passed");
        }
        else
        {
            Console.WriteLine("Test failed");
        }
    }
}

