using System;

class Program
{
    static void Main()
    {
        bool agePassed = CheckAge();
        bool ticketPassed = CheckTicket();

        ShowAccessResult(agePassed, ticketPassed);
    }

    // This method checks the age
    static bool CheckAge()
    {
        int age = 20;

        if (age >= 18)
        {
            return true;
        }
        else
        {
            return false;
        }
    }

    // This method checks the ticket
    static bool CheckTicket()
    {
        bool hasTicket = true;

        if (hasTicket == true)
        {
            return true;
        }
        else
        {
            return false;
        }
    }

    // This method prints the final result
    static void ShowAccessResult(bool agePassed, bool ticketPassed)
    {
        if (agePassed == true && ticketPassed == true)
        {
            Console.WriteLine("Access allowed");
        }
        else
        {
            Console.WriteLine("Access denied");
        }
    }
}
